esqlQuery.esql:
TS metrics-oracle_weblogic.otel-*
| WHERE weblogic.threadpool.threads.hogging IS NOT NULL
| STATS hogging_threads = MAX(LAST_OVER_TIME(weblogic.threadpool.threads.hogging))
    BY attributes.server
// Hogging threads have exceeded the "stuck thread max time" threshold
// but are not yet classified as stuck — a precursor to stuck threads
// Adjust threshold for environments with expected long-running requests
| WHERE hogging_threads > 0
| SORT hogging_threads DESC
